using Contoso.Services;

namespace Contoso.Services.Tests;

public interface IGreeter { string Greet(); }
public class Greeter : IGreeter { public string Greet() => "Hello"; }

public interface ILogger { void Log(string msg); }
public class FakeLogger : ILogger { public void Log(string msg) { } }

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_And_Resolve_Returns_RegisteredInstance()
    {
        var greeter = new Greeter();
        _registry.Register<IGreeter>(greeter);

        var resolved = _registry.Resolve<IGreeter>();

        Assert.AreSame(greeter, resolved);
    }

    [TestMethod]
    public void Resolve_ReturnsSameInstance_OnMultipleCalls()
    {
        var greeter = new Greeter();
        _registry.Register<IGreeter>(greeter);

        var first = _registry.Resolve<IGreeter>();
        var second = _registry.Resolve<IGreeter>();

        Assert.AreSame(first, second);
    }

    [TestMethod]
    public void Resolve_ReturnsNull_WhenServiceNotRegistered()
    {
        var result = _registry.Resolve<IGreeter>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void Clear_RemovesAllRegisteredServices()
    {
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IGreeter>());
        Assert.IsNull(_registry.Resolve<ILogger>());
        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Remove_RemovesOnlyTargetedService()
    {
        _registry.Register<IGreeter>(new Greeter());
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Remove<IGreeter>();

        Assert.IsNull(_registry.Resolve<IGreeter>());
        Assert.IsNotNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Register_OverwritesPreviousRegistration()
    {
        var first = new Greeter();
        var second = new Greeter();

        _registry.Register<IGreeter>(first);
        _registry.Register<IGreeter>(second);

        Assert.AreSame(second, _registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Register_ThrowsArgumentNullException_WhenServiceIsNull()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _registry.Register<IGreeter>(null!));
    }

    [TestMethod]
    public void ResolveRequired_ThrowsInvalidOperationException_WhenNotRegistered()
    {
        Assert.ThrowsExactly<InvalidOperationException>(() => _registry.ResolveRequired<IGreeter>());
    }

    [TestMethod]
    public void ResolveRequired_ReturnsService_WhenRegistered()
    {
        var greeter = new Greeter();
        _registry.Register<IGreeter>(greeter);

        var resolved = _registry.ResolveRequired<IGreeter>();

        Assert.AreSame(greeter, resolved);
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegisteredServices()
    {
        var greeter = new Greeter();
        var logger = new FakeLogger();
        _registry.Register<IGreeter>(greeter);
        _registry.Register<ILogger>(logger);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        CollectionAssert.Contains(all.ToList(), greeter);
        CollectionAssert.Contains(all.ToList(), logger);
    }

    [TestMethod]
    public void Remove_DoesNotThrow_WhenServiceNotRegistered()
    {
        _registry.Remove<IGreeter>();
    }
}

